order_details_subscription_status_cancelled = TextObject(bs_BA="Pretplata je otkazana dana: %1.", cs_CZ="Předplatné bylo zrušeno dne: %1.", da_DK="Abonnement blev opsagt til den: %1.", de_DE="Das Abonnement wurde gekündigt zum: %1.", el_GR="Η συνδρομή καταγγέλθηκε την: %1.", en_GB="The subscription has been cancelled with effect from: %1.", es_ES="La suscripción se canceló el: %1.", fi_FI="Tilaus on irtisanottu %1.", fr_FR="L'abonnement a été résilié au: %1.", hr_HR="Pretplata je otkazana: %1.", hu_HU="Az előfizetés a következő dátummal megszűnt: %1.", it_IT="L'abbonamento è stato disdetto dal %1.", nl_NL="Het abonnement werd opgezegd per: %1.", no_NO="Abonnementet ble sagt opp den: %1.", pl_PL="Abonament został wypowiedziany z dniem: %1.", pt_PT="A subscrição foi cancelada em: %1.", ro_RO="Abonamentul a fost reziliat în: %1.", ru_RU="Подписка отменена: %1.", sk_SK="Predplatné bolo zrušené k dátumu: %1.", sl_SI="Naročnina je bila odpovedana: %1.", sr_RS="Pretplata je otkazana dana: %1.", sv_SE="Abonnemanget sades upp: %1.", tr_TR="Abonelik şu tarihte iptal edildi: %1.", uk_UA="Підписку скасовано: %1.")
order_details_subscription_status_paused = TextObject(bs_BA="Pretplata je pauzirana zbog načina plaćanja koji je istekao ili je\nnevažeći. Aktualizirajte Vaš način plaćanja da biste obnovili Vašu\npretplatu.", cs_CZ="Vaše předplatné je pozastaveno z důvodu vypršelé nebo neplatné\nplatební metody. Aktualizujte prosím platební metodu a obnovte si\npředplatné.", da_DK="Abonnementet pauses på grund af en udløbet eller ugyldig\nbetalingsmåde. Opdater din betalingsmåde for at forny dit\nabonnement.", de_DE="Das Abonnement wird aufgrund einer abgelaufenen oder\nungültigen Zahlungsmethode pausiert. Bitte aktualisiere deine\nZahlungsmethode, um dein Abonnement zu erneuern.", el_GR="Η συνδρομή διακόπηκε προσωρινά εξαιτίας ληγμένης ή μη έγκυρης\nμεθόδου πληρωμής. Ενημερώστε τη μέθοδο πληρωμής σας, για να\nπαρατείνετε την ισχύ της συνδρομής σας.", en_GB="The subscription is being paused due to an expired or invalid\npayment method. Please update your payment method to renew\nyour subscription.", es_ES="La suscripción se ha pausado porque el método de pago ha\ncaducado o no es válido. Por favor, actualice su método de pago\npara renovar la suscripción.", fi_FI="Tilaus keskeytetään vanhentuneen tai virheellisen maksutavan\nvuoksi. Päivitä maksutapasi tilauksen uusimista varten.", fr_FR="L'abonnement est suspendu en raison d'un moyen de paiement\nexpiré ou non valide. Veuillez mettre à jour votre moyen de\npaiement pour renouveler votre abonnement.", hr_HR="Pretplata se otkazuje zbog isteklog ili nevažećeg načina plaćanja.\nAktualizirajte svoj način plaćanja kako biste obnovili pretplatu.", hu_HU="Az előfizetés lejárt vagy érvénytelen fizetési mód miatt szünetel.\nFrissítsd a fizetési módodat az előfizetés megújításához.", it_IT="L'abbonamento è stato sospeso a causa di un metodo di\npagamento scaduto o non valido. Si prega di aggiornare il metodo\ndi pagamento per rinnovare l'abbonamento.", nl_NL="Het abonnement wordt gepauzeerd op basis van een verlopen of\nongeldige betalingsmethode. Pas je betalingsmethode aan om je\nabonnement te vernieuwen.", no_NO="Abonnementet blir satt på pause på grunn av utløpt eller ugyldig\nbetalingsinformasjon. Du må oppdatere betalingsinformasjonen\nfor å fornye abonnementet.", pl_PL="Abonament zostaje wstrzymany ze względu na wygasłą lub\nnieprawidłową metodę płatności. Aby wznowić abonament,\nzaktualizuj swoją metodę płatności.", pt_PT="A subscrição encontra-se suspensa devido a um método de\npagamento expirado ou inválido. Atualiza o teu método de\npagamento para renovares a tua subscrição.", ro_RO="Abonamentul este pus în aşteptare din cauza unei metode de plată\nexpirate sau invalide. Vă rugăm actualizaţi metoda de plată, pentru\na reînnoi abonamentul.", ru_RU="Подписка приостановлена ​​из-за истекшего срока действия или\nнедействительного способа оплаты. Чтобы возобновить\nподписку, обновите способ оплаты.", sk_SK="Predplatné je pozastavené z dôvodu expirovanej alebo neplatnej\nplatobnej metódy. Prosím, aktualizujte svoju platobnú metódu, aby\nste mohli predplatné obnoviť.", sl_SI="Naročnina je bila zaustavljena, ker je način plačila potekel ali ni\nveljaven. Posodobite način plačila, da obnovite naročnino.", sr_RS="Pretplata je pauzirana zbog isteklog ili nevažećeg načina plaćanja.\nAžurirajte način plaćanja da biste obnovili Vašu pretplatu.", sv_SE="Abonnemanget pausas på grund av en utgången eller ogiltig\nbetalningsmetod. Uppdatera din betalningsmetod för att förnya\nabonnemanget.", tr_TR="Abonelik, süresi dolmuş veya geçersiz bir ödeme yöntemi nedeniyle\nduraklatıldı. Aboneliğini yenilemek için lütfen ödeme yöntemini\ngüncelle.", uk_UA="Підписку призупинено через закінчення строку дії або недійсний\nспосіб оплати. Щоб відновити підписку, оновіть спосіб оплати.")
order_details_subscription_status_unsubscribed = TextObject(bs_BA="Više ne postoji pretplata za proizvod. Datum isteka: %1.", cs_CZ="Produkt již není předplacen. Datum platnosti: %1.", da_DK="Du abonnerer ikke længere på produktet. Udløbsdato: %1.", de_DE="Das Produkt ist nicht mehr abonniert. Ablaufdatum: %1.", el_GR="Δεν υπάρχει πλέον συνδρομή για το προϊόν. Ημερομηνία λήξης:\n%1.", en_GB="You are no longer subscribed to this product. Expiry date:\n%1.", es_ES="Producto sin suscripción. Caducó el: %1.", fi_FI="Tuotteelle ei ole enää tilausta. Voimassaolo päättynyt: %1.", fr_FR="Vous n'êtes plus abonné à ce produit.\nDate d'expiration: %1.", hr_HR="Za proizvod više ne postoji pretplata. Datum isteka: %1.", hu_HU="A termék előfizetése megszűnt. Lejárat dátuma: %1.", it_IT="Il prodotto non è più in abbonamento. Data di scadenza: %1.", nl_NL="Geen abonnement meer voor dit product. Vervaldatum: %1.", no_NO="Du abonnerer ikke lenger på produktet. Utløpsdato: %1.", pl_PL="Nie ma już abonamentu na produkt.\nData wygaśnięcia: %1.", pt_PT="O produto já não está subscrito. Data de expiração: %1.", ro_RO="Produsul nu mai este abonat. Data expirării: %1.", ru_RU="Подписка на продукт больше не действует. Дата окончания срока\nдействия: %1.", sk_SK="Produkt už nie je predplatený. Dátum vypršania: %1.", sl_SI="Na produkt niste več naročeni. Datum poteka: %1.", sr_RS="Više ne postoji pretplata za proizvod. Datum isticanja: %1.", sv_SE="Du abonnerar inte längre på produkten. Utgångsdatum:\n%1.", tr_TR="Artık ürün abone değil. Son kullanma tarihi: %1.", uk_UA="Підписка на продукт більше не діє. Дата закінчення строку дії:\n%1.")
