shop_functions_detail_checkout_subscription_first_renewal_period_discount_price_text_years = TextObject(bs_BA="Prvih %1 godina %2 %3", cs_CZ="Prvních %1 let %2 %3", da_DK="De første %1 år %2 %3", de_DE="Erste %1 Jahre %2 %3", el_GR="Πρώτα %1 έτη %2 %3", en_GB="First %1 years %2 %3", es_ES="Primeros %1 años %2 %3", fi_FI="Ensimmäiset %1 vuotta %2 %3", fr_FR="%1 premières années %2 %3", hr_HR="Godina broj: %1 %2 %3", hu_HU="Első %1 év %2 %3", it_IT="Primi %1 anni %2 %3", nl_NL="Eerste %1 jaar %2 %3", no_NO="Første %1 år %2 %3", pl_PL="Pierwsze %1 lata %2 %3", pt_PT="Primeiros %1 anos %2 %3", ro_RO="Primii %1 ani %2 %3", ru_RU="Первые %1 года %2 %3", sk_SK="Prvých %1 rokov %2 %3", sl_SI="Prvih %1 let %2 %3", sr_RS="Prvih %1 godina %2 %3", sv_SE="Första %1 åren %2 %3", tr_TR="İlk %1 yıllar %2 %3", uk_UA="Перші %1 роки %2 %3")
shop_functions_detail_checkout_subscriptions_dialog_info_text = TextObject(bs_BA="Vaša pretplata se automatski produžava, ukoliko je ne otkažete. Pretplatu\nmožete uvijek otkazati s efektom za istek odgovarajućeg perioda važenja\nugovora. Već aktivirana licenca se ne može prenositi na druga vozila.", cs_CZ="Vaše předplatné se automaticky prodlouží, pokud jej nezrušíte. Předplatné\nmůžete kdykoli zrušit s účinností ke konci příslušného smluvního období. Již\naktivovanou licenci nelze převést na jiná vozidla.", da_DK="Dit abonnement forlænges automatisk, hvis du ikke opsiger det. Du kan til\nenhver tid opsige abonnementet med virkning fra den pågældende\naftaleperiodes udløb. En allerede aktiveret licens kan ikke overføres til andre\nbiler.", de_DE="Dein Abonnement wird automatisch verlängert, sofern du es nicht kündigst. Du\nkannst das Abonnement jederzeit mit Wirkung zum Ende der jeweiligen\nVertragslaufzeit kündigen. Eine bereits aktivierte Lizenz kann nicht auf andere\nFahrzeuge übertragen werden.", el_GR="Η ισχύς της συνδρομής σας θα παραταθεί αυτομάτως, εφόσον δεν την\nκαταγγείλετε. Μπορείte να καταγγείλεte τη συνδρομή ανά πάσα στιγμή με ισχύ\nαπό τη λήξη της αντίστοιχης περιόδου ισχύος της σύμβασης. Μια ήδη\nενεργοποιημένη συνδρομή δεν μπορεί να μεταφερθεί σε άλλα οχήματα.", en_GB="Your subscription will be extended automatically if you do not cancel it. You can\ncancel your subscription with effect from the end of the respective contract\nperiod at any time. Activated licences cannot be transferred to other vehicles.", es_ES="La suscripción se renovará automáticamente a menos que la cancele. Puede\ncancelar la suscripción en todo momento, con efecto a partir de que expire el\nperíodo contractual correspondiente. Cuando una licencia se activa, no se\npuede transferir a otros vehículos.", fi_FI="Tilauksesi jatkuu automaattisesti, mikäli et irtisano sitä. Voit milloin tahansa\nirtisanoa tilauksen päättymään kyseisen sopimusjakson loppuun. Jo aktivoitua\nlisenssiä ei voi siirtää toiseen autoon.", fr_FR="Votre abonnement sera automatiquement prolongé, sauf si vous le résiliez.\nVous pouvez résilier l'abonnement à tout moment, avec effet à compter de la\nfin de la période contractuelle concernée. Une licence déjà activée ne peut pas\nêtre transférée à d'autres véhicules.", hr_HR="Vaša pretplata se automatski produžava ako je ne otkažete. Pretplatu možete\notkazati u svakom trenutku uz uvažavanje navedenog roka trajanja ugovora. Već\naktivirana licenca ne može se prenijeti na druga vozila.", hu_HU="Az előfizetésed automatikusan meghosszabbodik, ha nem mondod le.\nBármikor lemondhatod az előfizetést; a lemondás a vonatkozó szerződéses\nidőszak végétől lép hatályba. A már aktivált licenc nem ruházható át más\njárművekre.", it_IT="L'abbonamento verrà rinnovato automaticamente se non viene disdetto\ndall'utente. L'utente può disdire l'abbonamento in qualsiasi momento con\neffetto al termine del rispettivo periodo di validità del contratto. Una licenza già\nattivata non può essere trasferita ad altre vetture.", nl_NL="Je abonnement wordt automatisch verlengd, tenzij je het opzegt. Je kunt het\nabonnement op elk moment per einde van de desbetreffende contractduur\nopzeggen. Een al geactiveerde licentie kan niet op andere voertuigen worden\novergedragen.", no_NO="Abonnementet forlenges automatisk så lenge du ikke sier det opp. Du kan når\nsom helst si opp abonnementet med virkning fra slutten av den inneværende\navtaleperioden. En aktivert lisens kan ikke overføres til andre biler.", pl_PL="Twój abonament zostanie automatycznie przedłużony, o ile go nie wypowiesz.\nAbonament można anulować w każdej chwili ze skutkiem na koniec okresu\nobowiązywania umowy. Aktywowana już licencja nie może być przenoszona na\ninne pojazdy.", pt_PT="A subscrição será automaticamente prolongada desde que não a canceles.\nPodes cancelar a subscrição em qualquer momento com efeito até ao final do\nrespetivo período de duração do contrato. Uma licença que já se encontre ativa\nnão pode ser transferida para outros veículos.", ro_RO="Abonamentul dumneavoastră se prelungeşte automat, dacă nu îl reziliaţi.\nPuteţi rezilia abonamentul în orice moment cu efecte la expirarea respectivei\nperioade contractuale. O licenţă deja activată nu poate fi transferată pe alte\nautovehicule.", ru_RU="Ваша подписка будет автоматически продлена, если вы ее не отмените. Вы\nможете отменить подписку в любое время с вступлением в силу по\nистечении соответствующего срока действия договора. Уже активированная\nлицензия не может быть передана на другие автомобили.", sk_SK="Vaše predplatné sa automaticky obnoví, pokiaľ ho nezrušíte. Predplatné môžete\nkedykoľvek zrušiť s účinnosťou ku koncu príslušného obdobia zmluvy. Už\naktivovanú licenciu nie je možné preniesť na iné vozidlo.", sl_SI="Vaša naročnina se avtomatsko podaljšuje, dokler je ne odpoveste. Naročnino\nlahko kadar koli odpoveste z učinkom ob koncu posameznega obdobja\nveljavnosti pogodbe. Že aktivirane licence ni mogoče prenesti na druga vozila.", sr_RS="Vaša pretplata će se automatsko produžiti, ukoliko je ne otkažete. Pretplatu\nmožete uvek da otkažete s efektom po isteku odgovarajućeg perioda važenja\nugovora. Već aktivirana licenca ne može da se prenosi na druga vozila.", sv_SE="Ditt abonnemang förlängs automatiskt om du inte säger upp det. Du kan när\nsom helst säga upp det med verkan från slutet av den aktuella avtalstiden. En\nredan aktiv licens kan inte överföras till andra fordon.", tr_TR="İptal etmediğin sürece aboneliğin otomatik olarak yenilenecektir. Aboneliği,\nilgili sözleşme süresinin sonundan itibaren geçerli olmak üzere iptal edebilirsin.\nÖnceden etkinleştirilmiş bir lisans başka araçlara devredilemez.", uk_UA="Ваша підписка буде автоматично продовжена, якщо ви її не скасуєте. Ви\nможете скасувати підписку в будь-який час із набранням чинності після\nзакінчення відповідного строку дії договору. Вже активована ліцензія не\nможе бути передана на інші автомобілі.")
shop_functions_detail_checkout_subscriptions_dialog_info_text_nar = TextObject(bs_BA="Vaša pretplata se automatski produžava, ukoliko je ne otkažete.\nMorate otkazati najmanje 15 dana prije početka sljedećeg perioda\nprodužetka kako vam ne bi bile naplaćene dodatne naknade. Već\naktivirana licenca se ne može prenijeti na druga vozila.", cs_CZ="Vaše předplatné se automaticky obnoví, pokud jej nezrušíte. Abyste\nse vyhnuli dalším poplatkům, musíte předplatné zrušit alespoň\n15 dní před začátkem dalšího období obnovení. Již aktivovanou\nlicenci nelze převést na jiná vozidla.", da_DK="Dit abonnement forlænges automatisk, såfremt du ikke opsiger\ndet. Du skal opsige det mindst 15 dage, før den næste\nforlængelsesperiode starter, for ikke at skulle betale ekstra. En\nlicens, der allerede er aktiveret, kan ikke overføres til andre biler.", de_DE="Dein Abonnement wird automatisch verlängert, sofern du nicht\nkündigst. Du musst mindestens 15 Tage vor dem Beginn des\nnächsten Verlängerungszeitraums kündigen, um keine zusätzliche\nGebühren in Rechnung gestellt zu bekommen. Eine bereits\naktivierte Lizenz kann nicht auf andere Fahrzeuge übertragen\nwerden.", el_GR="Η ισχύς της συνδρομής σας θα παραταθεί αυτομάτως, εφόσον δεν\nτην καταγγείλετε. Πρέπει να κάνετε την καταγγελία τουλάχιστον 15\nημέρες προν από την έναρξη της επόμενης χρονικής περιόδου\nπαράτασης, ούτως ώστε να μην σας χρεωθούν πρόσθετα τέλη. Μια\nάδεια που έχει ήδη ενεργοποιηθεί, δεν μπορεί να μεταβιβαστεί σε\nάλλα οχήματα.", en_GB="Your subscription will be extended automatically if you do not\nunsubscribe. You must unsubscribe at least 15 days before the\nstart of the next extension period so that you are not billed for any\nadditional charges. If a licence has already been activated, it cannot\nbe transferred to other vehicles.", es_ES="La suscripción se renovará automáticamente a menos que la\ncancele. Para evitar gastos adicionales, deberá cancelarla al menos\n15 días antes de que empiece el siguiente periodo de renovación.\nCuando una licencia se activa, no se puede transferir a otros\nvehículos.", fi_FI="Tilauksesi jatkuu automaattisesti, mikäli et irtisano sitä.\nLisämaksujen laskuttamisen välttämiseksi irtisanominen on\ntehtävä vähintään 15 päivää ennen seuraavan jatkokauden\nalkamista. Jo aktivoitua lisenssiä ei voi siirtää toiseen autoon.", fr_FR="Votre abonnement sera automatiquement prolongé, sauf si vous le\nrésiliez. Vous devez résilier au moins 15 jours avant le début de la\nprochaine période de renouvellement pour éviter de payer des frais\nsupplémentaires. Une licence déjà activée ne peut pas être\ntransférée à d'autres véhicules.", hr_HR="Vaša se pretplata automatski produžava ako je ne otkažete. Trebate\nje otkazati najmanje 15 dana prije početka sljedećeg perioda za\nproduženje kako ne biste platili nikakve dodatne naknade. Već\naktiviranu licencu nije moguće prenijeti na druga vozila.", hu_HU="Az előfizetésed automatikusan meghosszabbodik, ha nem mondod\nfel. A következő meghosszabbítási időszak kezdete előtt legalább\n15 nappal fel kell mondanod, hogy ne kerüljenek felszámításra\ntovábbi díjak. A már aktivált licenc nem ruházható át más\njárművekre.", it_IT="L'abbonamento verrà rinnovato automaticamente, se non viene\ndisdetto dall'utente. Per evitare l'addebito di costi aggiuntivi, è\nnecessario disdire l'abbonamento almeno 15 giorni prima\ndell'inizio del successivo periodo di rinnovo. Una licenza già attivata\nnon può essere trasferita ad altre vetture.", nl_NL="Je abonnement wordt automatisch verlengd, tenzij je het opzegt. Je\nmoet ten minste 15 dagen voor het begin van de volgende\nverlengingsperiode opzeggen, om te voorkomen dat er extra\nkosten in rekening worden gebracht. Een al geactiveerde licentie\nkan niet op andere voertuigen worden overgedragen.", no_NO="Abonnementet forlenges automatisk så lenge du ikke sier det opp.\nDu må si opp abonnementet minst 15 dager før neste\nforlengelsesperiode starter, for å unngå ekstra kostnader. En\naktivert lisens kan ikke overføres til andre biler.", pl_PL="Twój abonament zostanie automatycznie przedłużony, o ile go nie\nwypowiesz. Aby uniknąć naliczenia dodatkowych opłat, musisz\nwypowiedzieć abonament co najmniej 15 dni przed rozpoczęciem\nkolejnego okresu przedłużenia. Aktywowanego już abonamentu nie\nmożna przenosić na inne pojazdy.", pt_PT="A tua subscrição renova-se automaticamente, salvo cancelamento.\nTens de a cancelar pelo menos 15 dias antes do início do próximo\nperíodo de renovação, para não serem cobradas taxas adicionais.\nUma licença já ativada não pode ser transferida para outros\nveículos.", ro_RO="Abonamentul dumneavoastră se prelungeşte automat, dacă nu îl\nreziliaţi. Trebuie să reziliaţi cu cel puţin 15 zile înainte de următorul\ninterval de prelungire, pentru a evita facturarea unor taxe\nsuplimentare. O licenţă deja activată nu poate fi transferată pe alte\nautovehicule.", ru_RU="Ваша подписка будет автоматически продлена, если вы ее не\nотмените. Отменить подписку необходимо не менее чем за 15\nдней до начала следующего периода продления, чтобы\nизбежать дополнительных сборов. Уже активированную\nлицензию нельзя перенести на другие автомобили.", sk_SK="Vaše predplatné sa automaticky predĺži, pokiaľ ho nezrušíte. Musíte\nho zrušiť aspoň 15 dní pred začiatkom ďalšieho obdobia predĺženia,\naby vám neboli účtované ďalšie poplatky. Už aktivovanú licenciu nie\nje možné preniesť na iné vozidlo.", sl_SI="Vaša naročnina se avtomatsko podaljšuje, dokler je ne odpoveste.\nOdpovedati jo morate vsaj 15 dni pred začetkom naslednjega\nobdobja podaljšanja, da vam ne bodo zaračunali dodatnih stroškov. \nŽe aktivirane licence ni mogoče prenesti na druga vozila.", sr_RS="Vaša pretplata će se automatski produžiti, ako je niste otkazali.\nMorate da otkažete najmanje 15 dana pre početka sledećeg\nvremenskog perioda produžetka da ne biste imali dodatne troškove\nnaknada. Licenca koja je već aktivirana ne može da se prenosi na\ndruga vozila.", sv_SE="Ditt abonnemang förlängs automatiskt om du inte säger upp det.\nDu måste säga upp det minst 15 dagar innan nästa förlängda\nperiod börjar för att undvika ytterligare kostnader. En redan aktiv\nlicens kan inte överföras till andra fordon.", tr_TR="İptal etmediğin sürece aboneliğin otomatik olarak yenilenecektir.\nEk ücretlerden kaçınmak için, bir sonraki yenileme döneminin\nbaşlangıcından en az 15 gün önce iptal işlemini gerçekleştirmelisin.\nAktif hale getirilmiş bir lisans başka araçlara devredilemez.", uk_UA="Вашу підписку буде автоматично продовжено, якщо ви її не\nскасуєте. Скасувати підписку необхідно не менше ніж за 15 днів\nдо початку наступного періоду продовження, щоб уникнути\nдодаткових зборів. Вже активовану ліцензію не можна перенести\nна інші автомобілі.")
shop_functions_detail_checkout_variant_selection_auto_renew_checkbox_list_item_content_text_2 = TextObject(bs_BA="Licenca se automatski produžava. Tokom ovog perioda važenja se obračunava gore navedena cijena.\nLicenca se može otkazati preko myAudi aplikacije ili myAudi portala.", cs_CZ="Vaše licence bude automaticky prodloužena. Během této doby bude účtována výše uvedená cena.\nLicenci lze zrušit prostřednictvím aplikace myAudi nebo portálu myAudi.", da_DK="Din licens forlænges automatisk. I løbet af denne løbetid afregnes den ovennævnte pris. Licensen kan\nopsiges via myAudi-appen eller myAudi-portalen.", de_DE="Deine Lizenz wird automatisch verlängert. Während dieser Laufzeit wird der oben genannte Preis\nabgerechnet. Die Lizenz kann über die myAudi App oder das myAudi Portal gekündigt werden.", el_GR="Η άδειά σας θα παραταθεί αυτομάτως. Κατά τη διάρκεια ισχύος της, θα χρεώνεται η προαναφερθείσα\nτιμή. Η άδεια μπορεί να καταγγελθεί μέσω της εφαρμογής myAudi ή της διαδικτυακής πύλης myAudi.", en_GB="Your license will be extended automatically. The price stated above will be billed during this period.\nYou can cancel the license in the myAudi app or on the myAudi portal.", es_ES="Su licencia se renovará automáticamente. Durante el plazo en cuestión se cobrará el precio arriba\nmencionado. La licencia se puede cancelar en la App myAudi o en el portal myAudi.", fi_FI="Lisenssiäsi jatketaan automaattisesti. Tämän voimassaoloajan aikana veloitetaan yllä mainittu hinta.\nLisenssin voi irtisanoa myAudi-sovelluksessa tai myAudi-portaalissa.", fr_FR="Votre licence sera automatiquement renouvelée. Pendant cette période, le prix ci-dessus vous sera\nfacturé. Vous pouvez résilier la licence via l'application myAudi ou sur le portail myAudi.", hr_HR="Vaša se licenca automatski produžava. Tijekom tog vremena zaračunava se gore navedena cijena.\nLicencu možete otkazati preko myAudi aplikacije ili myAudi portala.", hu_HU="A licenced automatikusan meghosszabbodik. Ezen futamidő alatt a fenti ár kerül felszámításra. A\nlicencet a myAudi alkalmazáson vagy a myAudi portálon keresztül lehet lemondani.", it_IT="La licenza si rinnova automaticamente. Durante il periodo di validità verrà addebitato il prezzo sopra\nindicato. La licenza può essere disdetta tramite l'app myAudi o il portale myAudi.", nl_NL="Je licentie wordt automatisch verlengd. Gedurende deze termijn wordt de bovenstaande prijs in\nrekening gebracht. Je kunt de licentie opzeggen in de myAudi-app of het myAudi-portaal.", no_NO="Lisensen forlenges automatisk. I løpetiden avregnes den ovennevnte prisen. Du kan si opp lisensen i\nmyAudi-appen eller myAudi-portalen.", pl_PL="Licencja zostanie automatycznie przedłużona. W tym okresie naliczana będzie powyższa cena.\nLicencję można anulować w aplikacji myAudi lub na portalu myAudi.", pt_PT="A tua licença é automaticamente prolongada. Durante este período é cobrado o preço acima referido.\nA licença pode ser cancelada através da myAudi App ou do Portal Audi.", ro_RO="Licenţa dumneavoastră este prelungită automat. În timpul perioadei contractuale se facturează\npreţul de mai sus. Licenţa poate fi reziliată prin aplicaţia myAudi sau prin portalul myAudi.", ru_RU="Ваша лицензия будет продлена автоматически. В течение этого срока будет взиматься\nвышеупомянутая цена. Лицензию можно отменить через приложение myAudi или\nпортал myAudi.", sk_SK="Vaša licencia sa automaticky predĺži. Počas tohto obdobia sa bude účtovať vyššie uvedená cena.\nLicenciu je možné zrušiť prostredníctvom aplikácie myAudi alebo portálu myAudi.", sl_SI="Vaša licenca se avtomatsko podaljša. V tem času veljavnosti se obračuna zgoraj navedena cena.\nLicenco je mogoče odpovedati v aplikaciji myAudi ali na portalu myAudi.", sr_RS="Vaša licenca se automatski produžava. Tokom ovog perioda važenja obračunava se gore navedena\ncena. Licenca može da se otkaže preko aplikacije myAudi ili portala myAudi.", sv_SE="Din licens förlängs automatiskt. Under dess giltighetstid kommer ovanstående pris att debiteras.\nLicensen kan avslutas via myAudi-appen eller myAudi-portalen.", tr_TR="Lisansın otomatik olarak uzatılacaktır. Bu dönem içerisinde yukarıda belirtilen fiyat tahsil edilecektir.\nLisans, myAudi uygulaması veya myAudi portalı üzerinden iptal edilebilir.", uk_UA="Ваша ліцензія буде продовжена автоматично. Протягом цього строку дії буде стягуватися\nвищевказана ціна. Ліцензію можна скасувати через програму myAudi або портал myAudi.")
shop_functions_detail_checkout_variant_selection_auto_renew_checkbox_list_item_title_text = TextObject(bs_BA="Označite kvačicom ako se ova funkcija treba automatski produžiti kada\nistekne odabrano vrijeme trajanja.", cs_CZ="Pokud chcete, aby se tato funkce automaticky prodloužila po skončení\nzvoleného období, zaškrtněte toto políčko.", da_DK="Sæt et flueben, hvis denne funktion skal forlænges automatisk, når den\nvalgte løbetid slutter.", de_DE="Bitte setze den Haken, sofern diese Funktion automatisch verlängert werden\nsoll, wenn die gewählte Laufzeit endet.", el_GR="Επιλέξτε το πλαίσιο αν επιθυμείτε να ανανεωθεί αυτόματα αυτή η λειτουργία,\nόταν παρέλθει το επιλεγμένο χρονικό διάστημα.", en_GB="Please tick the box if you wish to automatically extend the function once the\nselected period has elapsed.", es_ES="Marque la casilla si desea que esta función se renueve automáticamente\ncuando termine la validez seleccionada.", fi_FI="Merkitse valintaruutu, jos haluat, että tätä toimintoa jatketaan\nautomaattisesti, kun valittu käyttöjakso päättyy.", fr_FR="Cochez la case si cette fonction doit être automatiquement prolongée à la fin\nde la durée de validité sélectionnée.", hr_HR="Stavite kvačicu ako ovu funkciju treba automatski produžiti nakon isteka\nodabranog vremena rada.", hu_HU="Jelöld be a négyzetet a funkció automatikus meghosszabbításához a\nkiválasztott időtartam lejártakor.", it_IT="Spuntare la casella se si desidera che la funzione venga pro­rogata\nautomaticamente al termine del periodo selezionato.", nl_NL="Plaats het vakje als deze functie automatisch moet worden verlengd wanneer\nde gekozen looptijd eindigt.", no_NO="Sett en hake hvis funksjonen skal forlenges automatisk etter at den valgte\nperioden utløper.", pl_PL="Zaznacz pole, jeśli chcesz, aby ta funkcja była automatycznie przedłużana\npo zakończeniu wybranego okresu.", pt_PT="Coloca o visto caso desejes prolongar automaticamente esta função quando\ntermina o período de validade.", ro_RO="Setaţi bifa, dacă doriţi prelungirea automată a acestei funcţii după expirarea\nduratei de valabilitate.", ru_RU="Поставьте галочку, если хотите, чтобы эта функция автом. продлевалась\nпо окончании выбранного срока.", sk_SK="Prosím, zadajte háčik, ak chcete, aby sa táto funkcia po skončení zvoleného\nobdobia automaticky predĺžila.", sl_SI="Označite, če želite, da se ta funkcija podaljša avtomatsko, ko poteče izbrani\nčas veljavnosti.", sr_RS="Označite kvačicom ako ova funkcija treba automatski da se produži kada\nistekne izabrano vreme trajanja.", sv_SE="Kryssa i rutan om du vill att funktionen ska förlängas automatiskt när den\nvalda giltighetstiden gått ut.", tr_TR="Bu fonksiyonun seçilen dönem sona erdiğinde otomatik olarak uzatılmasını\nistiyorsan lütfen kutuyu işaretle.", uk_UA="Поставте прапорець, якщо хочете, щоб ця функція була автомат.\nпродовжена після закінчення вибраного терміну.")
shop_functions_detail_checkout_variant_selection_information_subtitle_auto_renewal_text = TextObject(bs_BA="Označite ispod kvačicom za automatsko produženje funkcije.", cs_CZ="Zaškrtnutím políčka níže se funkce automaticky rozšíří.", da_DK="Sæt et flueben nederst for at forlænge funktionen automatisk.", de_DE="Setze den Haken unten, um die Funktion automatisch zu verlängern.", el_GR="Επιλέξτε το πλαίσιο κάτω, για να ανανεωθεί αυτόματα η λειτουργία.", en_GB="Tick the box below to automatically extend the function.", es_ES="Marque la casilla inferior para que la función se renueve automáticamente.", fi_FI="Merkitse alla oleva valintaruutu, jos haluat, että toimintoa jatketaan\nautomaattisesti.", fr_FR="Cochez la case ci-dessous pour prolonger automatiquement la fonction.", hr_HR="Stavite kvačicu dolje kako biste funkciju automatski produžili.", hu_HU="Jelöld be az alábbi négyzetet a funkció automatikus meghosszabbításához.", it_IT="Spuntare la casella in basso per prorogare automaticamente la funzione.", nl_NL="Plaats het vinkje beneden om de functie automatisch te verlengen.", no_NO="Sett en hake nedenfor hvis funksjonen skal forlenges automatisk.", pl_PL="Zaznacz pole poniżej, aby automatycznie przedłużyć funkcję.", pt_PT="Coloca o visto abaixo para prolongar automaticamente a função.", ro_RO="Setaţi bifa în partea de jos, pentru a prelungi automat funcţia.", ru_RU="Поставьте галочку, чтобы автоматически продлить функцию.", sk_SK="Zadajte háčik v spodnej časti, aby sa funkcia automaticky predĺžila.", sl_SI="Za avtomatsko podaljšanje funkcije označite spodaj.", sr_RS="Označite kvačicom ispod za automatsko produženje funkcije.", sv_SE="Kryssa i rutan nedan för att förlänga funktionen automatiskt.", tr_TR="Fonksiyonu otomatik olarak uzatmak için aşağıdaki kutuyu işaretle.", uk_UA="Поставте прапорець нижче, щоб автоматично продовжити функцію.")
